      { q: "Which test is used to identify an alkene?", options: ["Litmus test", "Bromine water test", "Flame test", "Limewater test"], answer: 1 },
      { q: "What is the chemical formula for ethanol?", options: ["CH₃OH", "C₂H₅OH", "C₃H₇OH", "C₂H₄"], answer: 1 },
      { q: "Crude oil is separated by:", options: ["Filtration", "Evaporation", "Fractional distillation", "Crystallisation"], answer: 2 },
      { q: "Fermentation converts sugar into:", options: ["Carbon dioxide only", "Ethanol and carbon dioxide", "Water and oxygen", "Methane and water"], answer: 1 }
