      { q: "What does NGO stand for?", options: ["National Government Organisation", "Non-Governmental Organisation", "New Growth Organisation", "National Growth Objective"], answer: 1 },
      { q: "Which of the following is a key area of community development?", options: ["Military training", "Water and sanitation", "International trade only", "Space exploration"], answer: 1 },
      { q: "Sustainable community development means:", options: ["Projects that require constant external funding", "Projects that communities can maintain without external support", "Only short-term projects", "Projects that benefit only the wealthy"], answer: 1 }
