      { q: "What does Ctrl+Z do in word processing?", options: ["Save the document", "Print the document", "Undo the last action", "Select all text"], answer: 2 },
      { q: "Justified text alignment means:", options: ["Text is aligned to the left only", "Text is aligned to the right only", "Text is aligned to both left and right margins", "Text is centred"], answer: 2 },
      { q: "What is the keyboard shortcut to SAVE a document?", options: ["Ctrl+P", "Ctrl+S", "Ctrl+A", "F12"], answer: 1 }
